  }
}

=== app.js ===
const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');

const app = express();
const PORT = process.env.PORT || 3000;

mongoose.connect('mongodb://localhost:27017/minimal-express-app', {
  useNewUrlParser: true,
  useUnifiedTopology: true
});

const userSchema = new mongoose.Schema({
  username: String,
  password: String
});

const itemSchema = new mongoose.Schema({
  name: String,
  description: String,
  userId: mongoose.Schema.Types.ObjectId
});

const User = mongoose.model('User', userSchema);
const Item = mongoose.model('Item', itemSchema);

app.use(bodyParser.urlencoded({ extended: true }));
app.use(session({
  secret: 'secret-key',
  resave: false,
  saveUninitialized: true
}));

app.get('/', (req, res) => {
  res.send('<h1>Welcome to the Minimal Express App</h1>');
});

app.post('/register', async (req, res) => {
  const { username, password } = req.body;
  const user = new User({ username, password });
  await user.save();
  res.send('User registered!');
});

app.post('/login', async (req, res) => {
  const { username, password } = req.body;
  const user = await User.findOne({ username, password });
  if (user) {
    req.session.userId = user._id;
    res.send('Logged in!');
  } else {
    res.send('Invalid credentials');
  }
});

app.post('/items', async (req, res) => {
  if (!req.session.userId) return res.status(401).send('Unauthorized');
  const { name, description } = req.body;
  const item = new Item({ name, description, userId: req.session.userId });
  await item.save();
  res.send('Item created!');
});

app.get('/items', async (req, res) => {
  if (!req.session.userId) return res.status(401).send('Unauthorized');
  const items = await Item.find({ userId: req.session.userId });
  res.json(items);
});

app.put('/items/:id', async (req, res) => {
  if (!req.session.userId) return res.status(401).send('Unauthorized');
  const { id } = req.params;
  const { name, description } = req.body;
  await Item.findByIdAndUpdate(id, { name, description });
  res.send('Item updated!');
});

app.delete('/items/:id', async (req, res) => {
  if (!req.session.userId) return res.status(401).send('Unauthorized');
  const { id } = req.params;
  await Item.findByIdAndDelete(id);
  res.send('Item deleted!');
});

app.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
});

